    {
      "keystrokes": "DEBIAN_FRONTEND=noninteractive apt-get install -y --no-install-recommends build-essential git cmake protobuf-compiler libprotobuf-dev libgoogle-glog-dev libgflags-dev libatlas-base-dev libhdf5-serial-dev libleveldb-dev liblmdb-dev libsnappy-dev libboost-all-dev ca-certificates wget python3\n",
      "duration": 20.0
    },
    {
      "keystrokes": "git clone https://github.com/BVLC/caffe.git /app/caffe\n",
      "duration": 8.0
    },
    {
      "keystrokes": "cd /app/caffe\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git checkout -q tags/1.0.0\n",
      "duration": 1.0
    },
    {
      "keystrokes": "cp Makefile.config.example Makefile.config\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sed -i 's/^#\\? CPU_ONLY.*/CPU_ONLY := 1/' Makefile.config\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sed -i 's/^#\\? USE_OPENCV.*/USE_OPENCV := 0/' Makefile.config\n",
      "duration": 0.1
