      "duration": 0.1
    },
    {
      "keystrokes": "GLOG_logtostderr=1 ./build/tools/caffe train --solver=examples/cifar10/cifar10_quick_solver.prototxt 2>&1 | tee /app/caffe/training_output.txt\n",
      "duration": 360.0
    },
    {
      "keystrokes": "ls -l /app/caffe/examples/cifar10/cifar10_quick_iter_500.caffemodel\n",
      "duration": 0.1
    },
    {
      "keystrokes": "python3 - << 'PY'\nimport re, sys, json\nlog = '/app/caffe/training_output.txt'\ns = open(log, 'r', errors='ignore').read()\n# Extract last reported train accuracy (from Train net output ... accuracy)\ntrain_accs = [float(x) for x in re.findall(r'Train net output #[0-9]+: accuracy = ([0-9.]+)', s)]\ntrain_acc = train_accs[-1] if train_accs else None\n# Extract final test accuracy (ideally at Iteration 500 testing) but fall back to last test accuracy\n# Test lines look like: Test net output #0: accuracy = 0.5\ntest_accs = [float(x) for x in re.findall(r'Test net output #[0-9]+: accuracy = ([0-9.]+)', s)]\ntest_acc = test_accs[-1] if test_accs else None\nok = None\nmsg = ''\nif test_acc is None:\n    ok = False\n    msg = 'No test accuracy found in log.'\nelse:\n    if train_acc is None:\n        msg = 'Train accuracy not found; proceeding to compare test accuracy to threshold only.'\n        ok = test_acc > 0.45\n    else:\n        ok = (test_acc > 0.45) and (test_acc >= train_acc - 0.05)\n        msg = f'train_acc={train_acc:.4f}, test_acc={test_acc:.4f}, threshold_ok={test_acc>0.45}, within_5pct={test_acc >= (train_acc-0.05):s}'\nprint(json.dumps({\"train_acc\": train_acc, \"test_acc\": test_acc, \"ok\": ok, \"message\": msg}))\nPY\n",
      "duration": 0.5
    }
  ],
  "task_complete": false
}

